// EditProfile.js
import React, { useEffect, useRef, useState } from "react";
import "./Profile.css"; // keep your existing CSS (works with this)

const API_BASE = (process.env.REACT_APP_API_BASE || "http://localhost:5000/api")
  .replace(/\/+$/, "");

// --- helpers ----------------------------------------------------
const getAuthHeader = () => {
  const token = localStorage.getItem("token");
  return token ? { Authorization: `Bearer ${token}` } : {};
};

async function fetchWithFallback({ method = "GET", paths, body, json = true, multipart = false }) {
  let lastErr;
  for (const path of paths) {
    try {
      const url = `${API_BASE}${path}`;
      const opts = {
        method,
        credentials: "include",
        headers: multipart
          ? { ...getAuthHeader() } // ❗ no Content-Type for multipart; browser sets it
          : {
              ...(json ? { "Content-Type": "application/json" } : {}),
              ...getAuthHeader(),
            },
        body: multipart ? body : json ? JSON.stringify(body) : body,
      };
      const res = await fetch(url, opts);
      // success range
      if (res.ok) {
        const ct = res.headers.get("content-type") || "";
        if (ct.includes("application/json")) return await res.json();
        return {};
      }
      // not ok: try next path
      lastErr = new Error(`HTTP ${res.status}`);
    } catch (e) {
      lastErr = e;
    }
  }
  throw lastErr || new Error("Request failed");
}

// --- component --------------------------------------------------
export default function EditProfile() {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [msg, setMsg] = useState("");

  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    addressLine1: "",
    addressLine2: "",
    city: "",
    state: "",
    zip: "",
    country: "",
    lat: "",
    lng: "",
    avatarUrl: "",
  });

  const [avatarPreview, setAvatarPreview] = useState("");
  const fileRef = useRef(null);

  const setVal = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  // load current user (tries multiple common endpoints)
  useEffect(() => {
    let alive = true;

    (async () => {
      setError("");
      setMsg("");
      setLoading(true);
      try {
        const data =
          (await fetchWithFallback({
            paths: ["/auth/me", "/users/me", "/me"],
          })) || {};

        // Try to locate the user object from the response
        const u = data.user || data || {};
        const fromLS = (() => {
          try {
            return JSON.parse(localStorage.getItem("user") || "{}");
          } catch {
            return {};
          }
        })();

        const email = u.email || fromLS.email || "";

        if (alive) {
          setForm((prev) => ({
            ...prev,
            name: u.name || fromLS.name || "",
            email,
            phone: u.phone || "",
            addressLine1: u.address?.line1 || "",
            addressLine2: u.address?.line2 || "",
            city: u.address?.city || "",
            state: u.address?.state || "",
            zip: u.address?.zip || "",
            country: u.address?.country || "",
            lat: u.location?.lat ?? "",
            lng: u.location?.lng ?? "",
            avatarUrl: u.avatarUrl || fromLS.avatarUrl || "",
          }));
          setAvatarPreview(u.avatarUrl || fromLS.avatarUrl || "");
        }
      } catch (e) {
        console.error(e);
        if (alive) setError("Failed to load profile.");
        // still prime email from localStorage if we can
        const fromLS = (() => {
          try {
            return JSON.parse(localStorage.getItem("user") || "{}");
          } catch {
            return {};
          }
        })();
        if (fromLS.email && alive) setVal("email", fromLS.email);
      } finally {
        if (alive) setLoading(false);
      }
    })();

    return () => {
      alive = false;
    };
  }, []);

  const grabLocation = () => {
    setError("");
    setMsg("");
    if (!navigator.geolocation) {
      setError("Geolocation not supported on this browser.");
      return;
    }
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setVal("lat", pos.coords.latitude.toFixed(6));
        setVal("lng", pos.coords.longitude.toFixed(6));
        setMsg("Location captured.");
      },
      (err) => {
        console.error(err);
        setError("Could not fetch your current location.");
      },
      { enableHighAccuracy: true, timeout: 10000 }
    );
  };

  const onSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    setError("");
    setMsg("");

    if (!form.name.trim()) {
      setSaving(false);
      setError("Please enter your name.");
      return;
    }

    const payload = {
      name: form.name.trim(),
      phone: form.phone.trim(),
      address: {
        line1: form.addressLine1.trim(),
        line2: form.addressLine2.trim(),
        city: form.city.trim(),
        state: form.state.trim(),
        zip: form.zip.trim(),
        country: form.country.trim(),
      },
      location:
        form.lat && form.lng
          ? { lat: Number(form.lat), lng: Number(form.lng) }
          : undefined,
    };

    try {
      // Try several common update endpoints until one works
      const data = await fetchWithFallback({
        method: "PUT",
        paths: ["/auth/me", "/users/me", "/profile"], // <— this avoids 404 issues
        body: payload,
        json: true,
      });

      // Sync localStorage so header/avatar etc. update
      const uLS = (() => {
        try {
          return JSON.parse(localStorage.getItem("user") || "{}");
        } catch {
          return {};
        }
      })();

      localStorage.setItem(
        "user",
        JSON.stringify({
          ...uLS,
          name: payload.name,
          avatarUrl: data?.avatarUrl || uLS.avatarUrl,
          phone: payload.phone,
        })
      );

      setMsg("Profile saved ✔");
    } catch (e) {
      console.error(e);
      setError(e.message || "Failed to save profile.");
    } finally {
      setSaving(false);
    }
  };

  const onPickAvatar = async (ev) => {
    const file = ev.target.files?.[0];
    if (!file) return;

    const localURL = URL.createObjectURL(file);
    setAvatarPreview(localURL);
    setError("");
    setMsg("");

    const fd = new FormData();
    fd.append("avatar", file);

    try {
      const data = await fetchWithFallback({
        method: "POST",
        paths: ["/auth/avatar", "/users/avatar", "/profile/avatar"],
        body: fd,
        multipart: true,
      });

      const url = data?.avatarUrl || "";
      if (url) {
        setVal("avatarUrl", url);
        setAvatarPreview(url);
      }

      // persist to localStorage
      const uLS = (() => {
        try {
          return JSON.parse(localStorage.getItem("user") || "{}");
        } catch {
          return {};
        }
      })();
      localStorage.setItem("user", JSON.stringify({ ...uLS, avatarUrl: url }));

      setMsg("Photo updated ✔");
    } catch (e) {
      console.error(e);
      setError(e.message || "Failed to upload photo.");
      // restore preview
      setAvatarPreview(form.avatarUrl || "");
    }
  };

  if (loading) {
    return (
      <div className="profile-wrap">
        <div className="card loading">Loading…</div>
      </div>
    );
  }

  return (
    <div className="profile-wrap">
      <div className="card">
        {/* Header */}
        <div className="top">
          <div className="avatar">
            <img
              src={
                avatarPreview ||
                "https://ui-avatars.com/api/?name=" +
                  encodeURIComponent(form.name || "User")
              }
              alt="avatar"
            />
            <button
              type="button"
              className="btn outline small"
              onClick={() => fileRef.current?.click()}
            >
              Change Photo
            </button>
            <input
              ref={fileRef}
              type="file"
              accept="image/*"
              hidden
              onChange={onPickAvatar}
            />
          </div>

          <div className="identity">
            <div className="title">{form.name || "Your Name"}</div>
            {/* email is shown, but disabled */}
            <div className="subtitle">{form.email || " "}</div>
          </div>
        </div>

        {/* Form */}
        <form className="form" onSubmit={onSave}>
          <div className="grid">
            <div className="field">
              <label>Name</label>
              <input
                value={form.name}
                onChange={(e) => setVal("name", e.target.value)}
                placeholder="Full name"
              />
            </div>

            <div className="field">
              <label>Email</label>
              <input value={form.email} disabled />
              <small className="muted">Email can’t be changed</small>
            </div>

            <div className="field">
              <label>Phone</label>
              <input
                value={form.phone}
                onChange={(e) => setVal("phone", e.target.value)}
                placeholder="Phone number"
                inputMode="tel"
              />
            </div>

            <div className="field">
              <label>Address line 1</label>
              <input
                value={form.addressLine1}
                onChange={(e) => setVal("addressLine1", e.target.value)}
                placeholder="House / Street"
              />
            </div>

            <div className="field">
              <label>Address line 2</label>
              <input
                value={form.addressLine2}
                onChange={(e) => setVal("addressLine2", e.target.value)}
                placeholder="Area / Landmark (optional)"
              />
            </div>

            <div className="field">
              <label>City</label>
              <input
                value={form.city}
                onChange={(e) => setVal("city", e.target.value)}
                placeholder="City"
              />
            </div>

            <div className="field">
              <label>State</label>
              <input
                value={form.state}
                onChange={(e) => setVal("state", e.target.value)}
                placeholder="State"
              />
            </div>

            <div className="field">
              <label>ZIP / PIN</label>
              <input
                value={form.zip}
                onChange={(e) => setVal("zip", e.target.value)}
                placeholder="Postal code"
                inputMode="numeric"
              />
            </div>

            <div className="field">
              <label>Country</label>
              <input
                value={form.country}
                onChange={(e) => setVal("country", e.target.value)}
                placeholder="Country"
              />
            </div>
          </div>

          <div className="loc-row">
            <div className="field sm">
              <label>Latitude</label>
              <input
                value={form.lat}
                onChange={(e) => setVal("lat", e.target.value)}
                placeholder="e.g. 17.3850"
              />
            </div>
            <div className="field sm">
              <label>Longitude</label>
              <input
                value={form.lng}
                onChange={(e) => setVal("lng", e.target.value)}
                placeholder="e.g. 78.4867"
              />
            </div>
            <button type="button" className="btn ghost" onClick={grabLocation}>
              Use Current Location
            </button>
          </div>

          {error && <div className="alert error">{error}</div>}
          {msg && <div className="alert ok">{msg}</div>}

          <div className="actions">
            <button className="btn primary" type="submit" disabled={saving}>
              {saving ? "Saving…" : "Save Changes"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
